+    (e: React.DragEvent) => {
+      e.preventDefault();
+      const file = e.dataTransfer.files[0];
+      if (file) handleFile(file);
+    },
+    [],
+  );
+
+  const handleFile = useCallback((file: File) => {
+    setFileName(file.name);
