+        try {
+          const header = parseRvfBinaryHeader(buf);
+          setManifest({
+            format: header.format || 'rvf-binary',
+            version: header.version || '?',
+            fileId: 'uploaded',
+            dimensions: 0,
+            metric: 'unknown',
